#!/usr/bin/env node
// AICOS Registry - Human-Readable Registry Generator
// Generates human/REGISTRY.md from index/INDEX.json
// Usage: node tools/generate-human-registry.js
// Output: human/REGISTRY.md (GENERATED - DO NOT EDIT)

const fs = require('fs');
const path = require('path');

const ROOT_DIR = path.join(__dirname, '..');
const INDEX_FILE = path.join(ROOT_DIR, 'index', 'INDEX.json');
const OUTPUT_FILE = path.join(ROOT_DIR, 'human', 'REGISTRY.md');

function generateRegistry() {
  const index = JSON.parse(fs.readFileSync(INDEX_FILE, 'utf-8'));
  
  // Group by type
  const errors = index.filter(c => c.type === 'error_pattern').sort((a, b) => a.id.localeCompare(b.id));
  const solutions = index.filter(c => c.type === 'solution_proof').sort((a, b) => a.id.localeCompare(b.id));
  const metas = index.filter(c => c.type === 'meta_principle').sort((a, b) => a.id.localeCompare(b.id));
  
  const lines = [];
  
  // Header
  lines.push('# AICOS Registry - Cards Overview');
  lines.push('');
  lines.push('<!-- GENERATED - DO NOT EDIT -->');
  lines.push('<!-- This file is auto-generated by tools/generate-human-registry.js -->');
  lines.push('<!-- Run: node tools/generate-human-registry.js -->');
  lines.push('');
  lines.push(`**Total Cards:** ${index.length} (${errors.length} errors, ${solutions.length} solutions, ${metas.length} meta)`);
  lines.push('');
  
  // Meta Cards Section
  if (metas.length > 0) {
    lines.push('## Meta Principles');
    lines.push('');
    lines.push('| ID | Token | Title | Domain | Status |');
    lines.push('|---|---|---|---|---|');
    for (const card of metas) {
      const domain = Array.isArray(card.domain) ? card.domain.join(', ') : card.domain;
      lines.push(`| ${card.id} | ${card.token} | ${escapeMd(card.title)} | ${domain} | ${card.status} |`);
    }
    lines.push('');
  }
  
  // Error Cards Section
  if (errors.length > 0) {
    lines.push('## Error Patterns');
    lines.push('');
    lines.push('| ID | Token | Title | Domain | Status | Fixes |');
    lines.push('|---|---|---|---|---|---|');
    for (const card of errors) {
      const domain = Array.isArray(card.domain) ? card.domain.join(', ') : card.domain;
      const fixes = card.fixes && card.fixes.length > 0 ? card.fixes.join(', ') : '-';
      lines.push(`| ${card.id} | ${card.token} | ${escapeMd(card.title)} | ${domain} | ${card.status} | ${fixes} |`);
    }
    lines.push('');
  }
  
  // Solution Cards Section
  if (solutions.length > 0) {
    lines.push('## Solution Proofs');
    lines.push('');
    lines.push('| ID | Token | Title | Domain | Status | Ready |');
    lines.push('|---|---|---|---|---|---|');
    for (const card of solutions) {
      const domain = Array.isArray(card.domain) ? card.domain.join(', ') : card.domain;
      const ready = card.copy_ready ? '✓' : '-';
      lines.push(`| ${card.id} | ${card.token} | ${escapeMd(card.title)} | ${domain} | ${card.status} | ${ready} |`);
    }
    lines.push('');
  }
  
  // Footer
  lines.push('---');
  lines.push('');
  lines.push('*Generated by AICOS Registry Tools*');
  lines.push('');
  
  fs.writeFileSync(OUTPUT_FILE, lines.join('\n'));
  console.log(`Generated ${OUTPUT_FILE}`);
}

function escapeMd(text) {
  return text.replace(/[|]/g, '\\|');
}

// Run
generateRegistry();
